 1	import * as React from 'react';
 2	
 3	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
 4	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { getTemplateBootSourceType } from '@kubevirt-utils/resources/template/hooks/useVmTemplateSource/utils';
 7	import { getVMBootSourceLabel } from '@kubevirt-utils/resources/vm/utils/source';
 8	import { Badge, Label, Split, SplitItem } from '@patternfly/react-core';
 9	
10	import './VirtualMachineTemplatesSource.scss';
11	
12	type VirtualMachineTemplatesSourceProps = {
13	  availableDatasources: Record<string, V1beta1DataSource>;
14	  availableTemplatesUID: Set<string>;
15	  cloneInProgressDatasources: Record<string, V1beta1DataSource>;
16	  template: V1Template;
17	};
18	
19	const VirtualMachineTemplatesSource: React.FC<VirtualMachineTemplatesSourceProps> = ({
20	  availableDatasources,
21	  availableTemplatesUID,
22	  cloneInProgressDatasources,
23	  template,
24	}) => {
25	  const { t } = useKubevirtTranslation();
26	  const bootSource = getTemplateBootSourceType(template);
27	  const dataSource =
28	    availableDatasources?.[
29	      `${bootSource?.source?.sourceRef?.namespace}-${bootSource?.source?.sourceRef?.name}`
30	    ];
31	  const bootSourceLabel = t(getVMBootSourceLabel(bootSource?.type, dataSource));
32	  const isBootSourceAvailable = availableTemplatesUID.has(template?.metadata?.uid);
33	
34	  const isCloningSource =
35	    !!cloneInProgressDatasources?.[
36	      `${bootSource?.source?.sourceRef?.namespace}-${bootSource?.source?.sourceRef?.name}`
37	    ];
38	
39	  return (
40	    <Split hasGutter>
41	      <SplitItem className="virtual-machine-templates-source__boot-source-label">
42	        {bootSourceLabel}
43	      </SplitItem>
44	      {isBootSourceAvailable && (
45	        <SplitItem>
46	          <Badge key="available-boot">{t('Source available')}</Badge>
47	        </SplitItem>
48	      )}
49	      {isCloningSource && (
50	        <SplitItem>
51	          <Label>{t('Clone in progress')}</Label>
52	        </SplitItem>
53	      )}
54	    </Split>
55	  );
56	};
57	
58	export default VirtualMachineTemplatesSource;

